on::from_millis(50)).await;\\n+\\n+    let mut client = AxonServiceClient::connect(format!(\\\"http://{addr}\\\"))\\n+        .await\\n+        .unwrap();\\n+\\n+    // Construct a request with the composite `tenant:database` header.\\n+    let mut req = tonic::Request::new(proto::CreateEntityRequest {\\n+        collection: \\\"grpc-items\\\".into(),\\n+        id: \\\"grpc-e-01\\\".into(),\\n+        data_json: json!({\\\"x\\\": 1}).to_string(),\\n+        actor: String::new(),\\n+    });\\n+    req.metadata_mut().insert(\\n+        \\\"x-axon-tenant-database\\\",\\n+        MetadataValue::try_from(\\\"acme:orders\\\").unwrap(),\\n+    );\\n+\\n+    let resp = client.create_entity(req).await.expect(\\\"grpc create should succeed\\\");\\n+    let entity = resp.into_inner().entity.unwrap();\\n+    assert_eq!(entity.id, \\\"grpc-e-01\\\");\\n+}\",\"stderr\":\"\",\"interrupted\":false,\"isImage\":false,\"noOutputExpected\":false}}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-opus-4-6\",\"id\":\"msg_01CoXLxTt8yLZ1FEn63npYic\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"tool_use\",\"id\":\"toolu_014QR2JtB3sv86aiyub3Ej9N\",\"name\":\"Bash\",\"input\":{\"command\":\"git diff c554186..0dfdab8 -- crates/axon-server/src/serve.rs crates/axon-api/src/handler.rs crates/axon-api/src/transaction.rs scripts/cutover-smoke.sh\",\"description\":\"Show remaining changed files\"},\"caller\":{\"type\":\"direct\"}}],\"stop_reason\":null,\"stop_sequence\":null,\"stop_details\":null,\"usage\":{\"input_tokens\":1,\"cache_creation_input_tokens\":10016,\"cache_read_input_tokens\":22407,\"cache_creation\":{\"ephemeral_5m_input_tokens\":0,\"ephemeral_1h_input_tokens\":10016},\"output_tokens\":33,\"service_tier\":\"standard\",\"inference_geo\":\"not_available\"},\"context_management\":null},\"parent_tool_use_id\":null,\"session_id\":\"0a9f1446-c2e0-4db8-b50e-318c50111461\",\"uuid\":\"f30a24df-6a1f-40f4-992f-2876bb86b4ff\"}\n{\"type\":\"user\",\"message\":{\"r